        },
        enrichmentUpdatedAt: new Date(),
        tags: {
          set: []
        }
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async findEnrichmentSourceById(id: string) {
    const note = await prisma.note.findUnique({
      where: {
        id
      },
      select: {
        id: true,
        title: true,
        markdown: true,
        enrichmentStatus: true,
        enrichmentAttempts: true
      }
    });

